__global__ void fused_matmul(float* A, float* B, float* C, int M, int N, int K) {
    int row = blockIdx.y * blockDim.y + threadIdx.y;
    int col_base = (blockIdx.x * blockDim.x + threadIdx.x) * 4;
    float acc0 = 0.0f;
    float acc1 = 0.0f;
    float acc2 = 0.0f;
    float acc3 = 0.0f;
    if (row < M && col_base + 3 < N) {
        for (int k = 0; k < K; k++) {
            float a_val = A[row * K + k];
            float4 b4 = *reinterpret_cast<float4*>(&B[k * N + col_base]);
            acc0 += a_val * b4.x;
            acc1 += a_val * b4.y;
            acc2 += a_val * b4.z;
            acc3 += a_val * b4.w;
        }
    }
    if (row < M && col_base + 3 < N) {
        C[row * N + (col_base + 0)] = acc0;
        C[row * N + (col_base + 1)] = acc1;
        C[row * N + (col_base + 2)] = acc2;
        C[row * N + (col_base + 3)] = acc3;
    }
}
